SELECT id, doctor_id, department_id, schedule_date, period,
       period_start, period_end, total_slots, slot_duration,
       register_fee, status, create_time, update_time
FROM schedule
WHERE doctor_id = #{doctorId}
  AND schedule_date = #{scheduleDate}
  AND period = #{period}

SELECT id, doctor_id, department_id, schedule_date, period, period_start, period_end, total_slots, slot_duration, register_fee, status, create_time, update_time FROM schedule WHERE id IN
#{item}
ORDER BY id ASC
